def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    result = []
    start = sorted_nums[0]

    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] == sorted_nums[i-1] + 1:
            continue
        if start != sorted_nums[i-1]:
            if start != sorted_nums[i-1]:
                result.append(f'{start}-{sorted_nums[i-2]}')
            else:
                result.append(str(start))
        result.append(str(sorted_nums[i]))
        start = sorted_nums[i]

    if start == sorted_nums[-1]:
        result[-1] = f'{result[-1]}-{start}'

    return ','.join(result)
